<span class="line"><span style="color:#E5C07B;">	oScript</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">type</span><span style="color:#56B6C2;"> =</span><span style="color:#98C379;"> &quot;text/javascript&quot;</span><span style="color:#ABB2BF;">;</span></span>
